3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  Sword: 1000,
14	  Amulet: 600,
15	  Staff: 800,
16	  Potion: 400,
17	  Rune: 250,
18	  Moonstone: 250,
19	};
20	
21	const FIRST_INSURANCE_PERCENT = 110;
22	const PROCESSING_FEE = 5;
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const CAP_MULTIPLIER = 2;
25	
26	type Item = { type: string; cursed?: boolean; enchantment?: number };
27	type Customer = { name: string; years: number; contracts: number };
28	
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
33	const BLOCK_OF_3_BASE_PREMIUM = 60;
34	const BLOCK_OF_3_SIZE = 3;
35	const CURSED_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
39	const HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE = 0.5;
40	
41	const enchantmentLevelOf = (item: Item | undefined): number =>
42	  item?.enchantment ?? 0;
43	
44	const isBlockOf3Components = (type: string, count: number): boolean =>
45	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
46	
47	const baseForGroup = (type: string, count: number): number =>
48	  isBlockOf3Components(type, count)
49	    ? BLOCK_OF_3_BASE_PREMIUM
50	    : BASE_PREMIUMS[type] * count;
51	
52	const countBy = <T>(items: T[], keyOf: (item: T) => string): Record<string, number> =>
53	  items.reduce<Record<string, number>>((counts, item) => {
54	    const key = keyOf(item);
55	    counts[key] = (counts[key] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	
59	const baseTotalFor = (items: Item[]): number =>
60	  Object.entries(countBy(items, (item) => item.type))
61	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
62	
63	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
64	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
65	
66	const cursedSurchargeFor = (item: Item): number =>
67	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
68	
69	const highEnchantmentSurchargeFor = (item: Item): number =>
70	  surchargeOnBase(item, enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
71	
72	const itemSurchargesFor = (items: Item[]): number =>
73	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
74	
75	const loyaltyDiscountFor = (customer: Customer, baseTotal: number): number =>
76	  customer.years >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
77	
78	const applyFirstInsurance = (baseTotal: number): number =>
79	  (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
80	
81	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
82	
83	const followUpDiscountFor = (isFollowUp: boolean, baseTotal: number): number =>
84	  isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
85	
86	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
87	  const baseTotal = baseTotalFor(items);
88	  const policyBase = applyFirstInsurance(baseTotal);
89	  const itemSurcharges = itemSurchargesFor(items);
90	  const loyaltyDiscount = loyaltyDiscountFor(customer, baseTotal);
91	  const followUpDiscount = followUpDiscountFor(isFollowUp, baseTotal);
92	  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
93	};
94	
95	type Policy = { items: Item[]; cap: number; remainingCap: number };
96	type Damage = { itemType: string; amount: number };
97	type ClaimStep = { type: "claim"; policy: number; incident: { damages: Damage[] } };
98	type QuoteStep = { type: "quote"; items: Item[] };
99	type Step = QuoteStep | ClaimStep;
100	type Scenario = { customer: Customer; steps: Step[] };
101	type ClaimResult = { payout: number; remainingCap: number };
102	type QuoteResult = { premium: number };
103	
104	const insuranceSumFor = (items: Item[]): number =>
105	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
106	
107	const payoutForDamage = (damage: Damage, items: Item[]): number => {
108	  const item = items.find((i) => i.type === damage.itemType);
109	  const isHighEnchantmentClaim = enchantmentLevelOf(item) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
110	  const reimbursable = isHighEnchantmentClaim
111	    ? damage.amount * HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE
112	    : damage.amount;
113	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
114	};
115	
116	const totalPayoutFor = (damages: Damage[], items: Item[]): number =>
117	  Math.floor(damages.reduce((total, damage) => total + payoutForDamage(damage, items), 0));
118	
119	const clampToCap = (amount: number, remainingCap: number): number =>
120	  Math.min(amount, remainingCap);
121	
122	const validateDamagesMatchPolicy = (damages: Damage[], items: Item[]): void => {
123	  const policyCounts = countBy(items, (item) => item.type);
124	  const damageCounts = countBy(damages, (damage) => damage.itemType);
125	  for (const [itemType, count] of Object.entries(damageCounts)) {
126	    if (count > (policyCounts[itemType] ?? 0)) {
127	      throw new Error(`Damage refers to item not covered by policy: ${itemType}`);
128	    }
129	  }
130	};
131	
132	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
133	  const policy = policies[step.policy];
134	  validateDamagesMatchPolicy(step.incident.damages, policy.items);
135	  const payout = clampToCap(totalPayoutFor(step.incident.damages, policy.items), policy.remainingCap);
136	  policy.remainingCap -= payout;
137	  return { payout, remainingCap: policy.remainingCap };
138	};
139	
140	const newPolicyFor = (items: Item[]): Policy => {
141	  const cap = CAP_MULTIPLIER * insuranceSumFor(items);
142	  return { items, cap, remainingCap: cap };
143	};
144	
145	const isKnownItemType = (type: string): boolean => type in BASE_PREMIUMS;
146	
147	const validateItemTypes = (items: Item[]): void => {
148	  const unknown = items.find((item) => !isKnownItemType(item.type));
149	  if (unknown) {
150	    throw new Error(`Unknown item type: ${unknown.type}`);
151	  }
152	};
153	
154	const processQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean, policies: Policy[]): QuoteResult => {
155	  validateItemTypes(step.items);
156	  policies.push(newPolicyFor(step.items));
157	  return { premium: quotePremium(step.items, customer, isFollowUp) };
158	};
159	
160	export function processScenario(scenario: any): unknown {
161	  const policies: Policy[] = [];
162	  const results = (scenario.steps as Step[]).map((step, index) =>
163	    step.type === "claim"
164	      ? processClaim(step, policies)
165	      : processQuote(step, scenario.customer, index > 0, policies),
166	  );
167	  return { results };
168	}
